use tauri::{AppHandle, Manager};

fn store_from_app(app: &AppHandle) -> Result<&FileStore, String> {
    app.try_state::<FileStore>()
        .map(|s| s.inner())
        .ok_or_else(|| "Secrets store not initialised".to_string())
}

fn app_secrets_dir(app: &AppHandle) -> Result<PathBuf, String> {
    app.path()
        .app_config_dir()
        .map_err(|e| format!("nepodaЕ™ilo se najГ­t adresГЎЕ™ nastavenГ­: {e}"))
}

#[tauri::command]
pub fn set_api_key(app: AppHandle, connection_id: String, key: String) -> Result<(), String> {
    store_from_app(&app)?.set(&connection_id, &key)
}

#[tauri::command]
pub fn delete_api_key(app: AppHandle, connection_id: String) -> Result<(), String> {
    store_from_app(&app)?.delete(&connection_id)
}

#[tauri::command]
pub fn has_api_key(app: AppHandle, connection_id: String) -> Result<bool, String> {
    Ok(store_from_app(&app)?.get(&connection_id)?.is_some())
}

/// Internal helper for other commands (e.g. chat_complete) that need the
/// actual key value. Never exposed as a Tauri command itself.
pub fn get_api_key(connection_id: &str) -> Result<Option<String>, String> {
    // This is called from async contexts without AppHandle вЂ” fall back to
    // direct file read.
    let dir = dirs_next().ok_or("nepodaЕ™ilo se najГ­t domovskГЅ adresГЎЕ™")?;
    let store = FileStore::new(dir);
    store.get(connection_id)
}

fn dirs_next() -> Option<PathBuf> {
    // Use the same config dir logic as tauri would
    if let Ok(dir) = std::env::var("APPDATA") {
        Some(PathBuf::from(dir).join("com.morthos.mysillytavern"))
    } else if let Some(home) = dirs::home_dir() {
        if cfg!(target_os = "macos") {
            Some(home.join("Library/Application Support/com.morthos.mysillytavern"))
        } else {
            // Linux and others: XDG_CONFIG_HOME or ~/.config
            if let Ok(xdg) = std::env::var("XDG_CONFIG_HOME") {
                Some(PathBuf::from(xdg).join("com.morthos.mysillytavern"))
            } else {
                Some(home.join(".config/com.morthos.mysillytavern"))
            }
        }
    } else {
        None
    }
}

/// Initialise the secrets store with the app's config directory.
/// Called from `run()` before any command can access keys.
pub fn init_store(app: &AppHandle) -> Result<(), String> {
    let dir = app_secrets_dir(app)?;
    let store = FileStore::new(dir);
    app.manage(store);
    Ok(())
}

import { useEffect } from "react";
import { HashRouter, Navigate, Route, Routes } from "react-router-dom";

import { getAutoBackupEnabled, getAutoBackupMaxCount, runAutoBackup } from "./db/backup";
import { runSyncOnStartup } from "./db/syncReader";
import { useSettingsStore } from "./stores/settingsStore";
import { CardEditor } from "./ui/characters/CardEditor";
import { GalleryScreen } from "./ui/characters/GalleryScreen";
import { ChatListScreen } from "./ui/chat/ChatListScreen";
import { ChatScreen } from "./ui/chat/ChatScreen";
import { AppShell } from "./ui/layout/AppShell";
import { LorebookEditor } from "./ui/lorebooks/LorebookEditor";
import { LorebooksListScreen } from "./ui/lorebooks/LorebooksListScreen";
import { PersonasScreen } from "./ui/personas/PersonasScreen";
import { SettingsScreen } from "./ui/settings/SettingsScreen";

function App() {
  const { hydrated, hydrate } = useSettingsStore();

  useEffect(() => {
    void hydrate();
  }, [hydrate]);

  // Startup auto-backup (M14.1) вЂ” driven from the frontend so it can respect
  // the settings stored in SQLite and checkpoint the WAL before zipping.
  useEffect(() => {
    void (async () => {
      try {
        if (await getAutoBackupEnabled()) {
          await runAutoBackup(await getAutoBackupMaxCount());
        }
      } catch (err) {
        console.warn("startup auto-backup failed:", err);
      }
    })();
  }, []);

  // Startup sync (M14) вЂ” scan and apply foreign device journals after DB is ready.
  useEffect(() => {
    if (!hydrated) return;
    void (async () => {
      try {
        await runSyncOnStartup();
      } catch (err) {
        console.warn("[sync] startup sync failed:", err);
      }
    })();
  }, [hydrated]);

  if (!hydrated) {
    return null;
  }

  return (
    <HashRouter>
      <AppShell>
        <Routes>
          <Route path="/" element={<ChatListScreen />} />
          <Route path="/chat/:id" element={<ChatScreen />} />
          <Route path="/characters" element={<GalleryScreen />} />
          <Route path="/characters/:id" element={<CardEditor />} />
          <Route path="/personas" element={<PersonasScreen />} />
          <Route path="/lorebooks" element={<LorebooksListScreen />} />
          <Route path="/lorebooks/:id" element={<LorebookEditor />} />
          <Route path="/settings" element={<SettingsScreen />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </AppShell>
    </HashRouter>
  );
}

export default App;

import { useSyncExternalStore } from "react";

function subscribe(callback: () => void): () => void {
  window.addEventListener("online", callback);
  window.addEventListener("offline", callback);
  return () => {
    window.removeEventListener("online", callback);
    window.removeEventListener("offline", callback);
  };
}

function getSnapshot(): boolean {
  return navigator.onLine;
}

/** Tracks `navigator.onLine` reactively via the browser's online/offline
 * events, so the UI can show a clear "you're offline" state instead of a
 * confusing generic network error (plan В§9). */
export function useOnlineStatus(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, () => true);
}

